ControlPropertyState.AutoRuleBindingString:
Patch(
    ITCM,
    itemSeleccionadoT,
    {
        TipoIR: { Value: DdEditarTipo_T.Selected.Value },
        Categoria: { Value: DdEditarCat_T.Selected.Value },
        AgentDesign: If(
            !IsBlank(varAgenteSeleccionadoT),
            { Claims: "i:0#.f|membership|" & varAgenteSeleccionadoT.Correo, DisplayName: varAgenteSeleccionadoT.Título, Email: varAgenteSeleccionadoT.Correo },
            itemSeleccionadoT.AgentDesign
        )
    }
);
Notify("Datos actualizados correctamente", NotificationType.Success);
UpdateContext({mostrarModalEditarT: false, varAgenteSeleccionadoT: Blank()})
